def find_kth(A, B, k):
    l = len(A)
    m = len(B)

    # Ensure A is the smaller array to optimize the search
    if l > m:
        return find_kth(B, A, k)

    # Base cases
    if m == 0:
        return B[k - 1]
    if k == 1:
        return min(A[0], B[0])

    # Calculate partition points
    i = min(l, k // 2)
    j = k - i

    # If x_i is smaller than y_j-1, ignore left half of A and consider right half of B
    if A[i - 1] < B[j - 1]:
        return find_kth(A[i:], B, k - i)
    # If y_j is smaller than x_i-1, ignore right half of B and consider left half of A
    elif A[i - 1] > B[j - 1]:
        return find_kth(A, B[j:], k - j)
    # If x_i equals y_j, return x_i
    else:
        return A[i - 1]

def find_kth(A, B, k):
    # Base cases
    if len(A) == 0:
        return B[k - 1]
    if len(B) == 0:
        return A[k - 1]

    # Find mid points in both arrays
    mid_a = len(A) // 2
    mid_b = len(B) // 2

    # Compare elements at mid points
    if A[mid_a] <= B[mid_b]:
        # If mid_a is less than or equal to mid_b, ignore left half of A
        return find_kth(A[mid_a + 1:], B, k - mid_a - 1)
    else:
        # If mid_a is greater than mid_b, ignore right half of B
        return find_kth(A, B[mid_b + 1:], k - mid_b - 1)

